INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 1, 62, 2, 0.0, "2025/01/31 12:00:00", 1, 1000001, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 1, 62, 2, 0.0, "2025/01/31 12:00:00", 2, 1000002, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 1, 63, 2, 0.0, "2025/01/31 12:00:00", 3, 1000003, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 1, 63, 2, 0.0, "2025/01/31 12:00:00", 4, 1000004, "報酬がもらえますよ！\nチェックしてみてください", 0.0, "2030/01/01 14:59:59", 2, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 1, 64, 1, 0.0, "2025/01/31 12:00:00", 5, 1000005, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, "2030/01/01 14:59:59", 2, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 1, 64, 2, 0.0, "2025/01/31 12:00:00", 6, 1000006, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 1, 64, 1, 0.0, "2025/01/31 12:00:00", 7, 1000007, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, "2030/01/01 14:59:59", 2, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ラビリスタ", 10201, 61, 7, -6.0, "2025/01/31 12:00:00", 101, 1020101, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 5.18, "2030/01/01 14:59:59", 3, 133701);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "クリスティーナ", 10201, 61, 2, -2.0, "2025/01/31 12:00:00", 201, 1020102, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 8.77, "2030/01/01 14:59:59", 1, 133901);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ネネカ", 10201, 61, 1, 0.0, "2025/01/31 12:00:00", 301, 1020103, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 15.5, "2030/01/01 14:59:59", 6, 133801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ランファ", 10202, 61, 5, 0.0, "2025/02/28 12:00:00", 101, 1020201, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 9.061, "2030/01/01 14:59:59", 2, 134301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "チカ", 10202, 61, 2, 0.0, "2025/02/28 12:00:00", 201, 1020202, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 7.699, "2030/01/01 14:59:59", 1, 134401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "アオイ", 10203, 61, 2, 0.0, "2025/03/31 12:00:00", 101, 1020301, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 8.595, "2030/01/01 14:59:59", 1, 134601);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "クローチェ", 10203, 61, 2, 0.0, "2025/03/31 12:00:00", 201, 1020302, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 7.758, "2030/01/01 14:59:59", 1, 134501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ルイズマリー", 10204, 61, 6, 0.0, "2025/04/30 12:00:00", 101, 1020401, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 7.0, "2030/01/01 14:59:59", 2, 132302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "イロハ", 10204, 61, 2, 0.0, "2025/04/30 12:00:00", 201, 1020402, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 7.904, "2030/01/01 14:59:59", 1, 132402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ソノ", 10204, 61, 2, 0.0, "2025/04/30 12:00:00", 301, 1020403, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 8.487, "2030/01/01 14:59:59", 4, 132502);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "カノン", 10205, 61, 2, 0.0, "2025/05/31 12:00:00", 101, 1020502, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 8.763, "2030/01/01 14:59:59", 1, 134901);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ツムギ", 10205, 61, 3, 0.0, "2025/05/31 12:00:00", 201, 1020503, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 6.417, "2030/01/01 14:59:59", 1, 134801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "エリス", 10206, 61, 7, 0.0, "2025/06/30 12:00:00", 101, 1020601, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 10.335, "2030/01/01 14:59:59", 3, 135001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "シェフィ", 10206, 61, 4, 0.0, "2025/06/30 12:00:00", 201, 1020602, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 6.281, "2030/01/01 14:59:59", 2, 135101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "プレシア", 10206, 61, 2, 0.0, "2025/06/30 12:00:00", 301, 1020603, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 12.244, "2030/01/01 14:59:59", 1, 135201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "クリア", 10207, 61, 8, 0.0, "2025/07/31 12:00:00", 101, 1020701, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 6.339, "2030/01/01 14:59:59", 2, 135301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "アネモネ", 10207, 61, 9, 0.0, "2025/07/31 12:00:00", 201, 1020702, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 8.184, "2030/01/01 14:59:59", 7, 135401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "アイラ", 10208, 61, 2, 0.0, "2025/08/31 12:00:00", 101, 1020801, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 3.906, "2030/01/01 14:59:59", 9, 129101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "シナツ", 10208, 61, 2, 0.0, "2025/08/31 12:00:00", 201, 1020802, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 14.465, "2030/01/01 14:59:59", 1, 129201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ヒヨリ", 10208, 61, 3, 0.0, "2025/08/31 12:00:00", 301, 1020803, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 8.662, "2030/01/01 14:59:59", 4, 100101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "レイ", 10208, 61, 3, 0.0, "2025/08/31 12:00:00", 401, 1020804, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 10.915, "2030/01/01 14:59:59", 1, 100301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ユキノ", 10209, 61, 7, 0.0, "2025/09/30 12:00:00", 101, 1020901, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 6.042, "2030/01/01 14:59:59", 1, 135802);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "サツキ", 10209, 61, 1, 0.0, "2025/09/30 12:00:00", 201, 1020902, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 9.402, "2030/01/01 14:59:59", 4, 135903);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ルルィ", 10209, 61, 1, 0.0, "2025/09/30 12:00:00", 301, 1020903, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8.16, "2030/01/01 14:59:59", 8, 136902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "カスミ", 10210, 61, 2, 0.0, "2025/10/31 12:00:00", 101, 1021001, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 5.0, "2030/01/01 14:59:59", 3, 137401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "アラクネ", 10210, 61, 1, 0.0, "2025/10/31 12:00:00", 201, 1021002, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 8.12, "2030/01/01 14:59:59", 4, 136001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ナーナ", 10210, 61, 2, 0.0, "2025/10/31 12:00:00", 301, 1021003, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 6.386, "2030/01/01 14:59:59", 4, 136202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ユイ", 10211, 61, 4, 0.0, "2025/11/30 12:00:00", 101, 1021101, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 7.438, "2030/01/01 14:59:59", 3, 136402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ミソラ", 10211, 61, 5, 0.0, "2025/11/30 12:00:00", 201, 1021102, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 8.35, "2030/01/01 14:59:59", 1, 136302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "シズル", 10212, 61, 2, 0.0, "2025/12/31 12:00:00", 101, 1021201, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 5.0, "2030/01/01 14:59:59", 1, 136501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "リノ", 10212, 61, 2, 0.0, "2025/12/31 12:00:00", 201, 1021202, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 5.25, "2030/01/01 14:59:59", 1, 137902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ラビリスタ", 10212, 61, 2, 0.0, "2025/12/31 12:00:00", 301, 1021203, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 7.5, "2030/01/01 14:59:59", 1, 106801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ライラエル", 10213, 61, 2, 0.0, "2026/01/31 12:00:00", 101, 1021301, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 8.204, "2030/01/01 14:59:59", 1, 126501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ネフィ＝ネラ", 10213, 61, 2, 0.0, "2026/01/31 12:00:00", 201, 1021302, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 7.176, "2030/01/01 14:59:59", 1, 129701);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ヴァイオレット", 10213, 61, 5, 0.0, "2026/01/31 12:00:00", 301, 1021303, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 8.602, "2030/01/01 14:59:59", 1, 133101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ライラエル", 10213, 61, 3, 0.0, "2026/02/06 12:00:00", 102, 1021304, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 10.14, "2030/01/01 14:59:59", 1, 138101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ネフィ＝ネラ", 10213, 61, 7, 0.0, "2026/02/06 12:00:00", 202, 1021305, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 10.152, "2030/01/01 14:59:59", 1, 138201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ヴァイオレット", 10213, 61, 3, 0.0, "2026/02/06 12:00:00", 302, 1021306, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 9.688, "2030/01/01 14:59:59", 4, 138001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ペコリーヌ", 10213, 61, 1, 0.0, "2026/02/12 12:00:00", 401, 1021307, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 5.928, "2030/01/01 14:59:59", 2, 138301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ワカナ", 10214, 61, 2, 0.0, "2026/02/28 12:00:00", 101, 1021401, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 9.19, "2030/01/01 14:59:59", 4, 138702);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "シオリ", 10214, 61, 3, 0.0, "2026/02/28 12:00:00", 201, 1021402, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 8.724, "2030/01/01 14:59:59", 1, 138802);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "グレイス", 10215, 61, 1, 0.0, "2026/03/31 12:00:00", 101, 1021501, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 7.758, "2030/01/01 14:59:59", 4, 138902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "キョウカ", 10215, 61, 4, 0.0, "2026/03/31 12:00:00", 201, 1021502, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 6.375, "2030/01/01 14:59:59", 6, 139002);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, "ルルィ", 10215, 61, 1, 0.0, "2026/03/31 12:00:00", 301, 1021503, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 6.173, "2030/01/01 14:59:59", 6, 136902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 2, 62, 2, 0.0, "2026/04/10 12:00:00", 1, 2000001, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 3.414, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 2, 62, 2, 0.0, "2026/04/10 12:00:00", 2, 2000002, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 2, 63, 2, 0.0, "2026/04/10 12:00:00", 3, 2000003, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, "カリン", 2, 63, 2, 0.0, "2026/04/10 12:00:00", 4, 2000004, "報酬がもらえますよ！\nチェックしてみてください", 0.0, "2030/01/01 14:59:59", 2, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 2, 64, 1, 0.0, "2026/04/10 12:00:00", 5, 2000005, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2.12, "2030/01/01 14:59:59", 2, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 2, 64, 2, 0.0, "2026/04/10 12:00:00", 6, 2000006, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1.68, "2030/01/01 14:59:59", 1, 190801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, "カリン", 2, 64, 1, 0.0, "2026/04/10 12:00:00", 7, 2000007, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2.33, "2030/01/01 14:59:59", 2, 190801);
